$(document).ready(function(){$('#hamburger-btn').on('click',function(){$(this).toggleClass('open');$('#mobile-menu').toggleClass('open');});$('#mobile-menu .mobile-menu-link').on('click',function(){$('#hamburger-btn').removeClass('open');$('#mobile-menu').removeClass('open');});$('#nav-slider').slick({slidesToShow:5,slidesToScroll:1,asNavFor:'#main-slider',focusOnSelect:true,arrows:false,responsive:[{breakpoint:768,settings:{slidesToShow:4}},{breakpoint:480,settings:{slidesToShow:3}}]});$('#main-slider').slick({slidesToShow:1,slidesToScroll:1,arrows:false,fade:true,cssEase:'linear',asNavFor:'#nav-slider'});$('#nav-prev').on('click',function(){$('#main-slider').slick('slickPrev');});$('#nav-next').on('click',function(){$('#main-slider').slick('slickNext');});var modalInit=false;function openModal(idx){if(!modalInit){$('#modal-slider').slick({slidesToShow:1,slidesToScroll:1,arrows:true,fade:true,cssEase:'linear',initialSlide:idx || 0,prevArrow:'<button class="modal-nav-arrow modal-nav-arrow--prev">&#8592;</button>',nextArrow:'<button class="modal-nav-arrow modal-nav-arrow--next">&#8594;</button>'});modalInit=true;}else{$('#modal-slider').slick('slickGoTo',idx || 0,true);}new bootstrap.Modal(document.getElementById('galleryModal')).show();}$('#main-slider').on('click','.main-slide-img',function(){openModal($('#main-slider').slick('slickCurrentSlide'));});document.getElementById('galleryModal').addEventListener('shown.bs.modal',function(){if(modalInit)$('#modal-slider').slick('setPosition');});$('a[href^="#"]').on('click',function(e){var href=this.getAttribute('href');if(href==='#')return;var $t=$(href);if($t.length){e.preventDefault();$('html,body').animate({scrollTop:$t.offset().top - 80},450);}});});